package main

import (
	"html/template"
	"net/http"
	"time"
)

type Comment struct {
	Author  string
	Content template.HTML
	PostedAt time.Time
}

var comments = []Comment{
	{
		Author:  "Alice",
		Content:  template.HTML("Hello, <b>world</b>!"),
		PostedAt: time.Now().Add(-2 * time.Hour),
	},
	{
		Author:  "Bob",
		Content:  template.HTML("This is <i>italic</i> and <strong>bold</strong>."),
		PostedAt: time.Now().Add(-1 * time.Hour),
	},
}

var tpl = template.Must(template.New("comments").Parse(`
<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<title>User Comments</title>
</head>
<body>
	<h1>User Comments</h1>
	<ul>
		{{range .}}
		<li>
			<p><strong>{{.Author}}</strong> <em>{{.PostedAt.Format "2006-01-02 15:04:05"}}</em></p>
			<div>{{.Content}}</div>
		</li>
		{{end}}
	</ul>
</body>
</html>
`))

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	_ = tpl.Execute(w, comments)
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	_ = http.ListenAndServe(":8080", nil)
}